document.addEventListener("DOMContentLoaded", function () {
    const fileContainer = document.querySelector(".field-apk_file");
    if (!fileContainer) return;

    // Find the actual input generated by Django
    const originalInput = fileContainer.querySelector('input[type="file"]');
    if (!originalInput) return;

    // Hide standard django widget stuff
    const djangoWidget = fileContainer.querySelector('.file-upload');
    if (djangoWidget) djangoWidget.style.display = 'none';

    // Create the Dropzone UI
    const dropzoneHtml = `
        <div class="apk-dropzone-container">
            <div class="apk-dropzone" id="apk-dropzone">
                <div class="apk-dropzone-icon">📦</div>
                <div class="apk-dropzone-title">Drag & Drop APK File Here</div>
                <div class="apk-dropzone-subtitle">or click to browse from your computer (Max 200MB)</div>
                <button type="button" class="button" style="background:rgba(255,255,255,0.1);color:white;border:none;padding:8px 16px;border-radius:8px;font-weight:600;cursor:pointer;">Select File</button>
            </div>
            
            <div class="apk-file-preview" id="apk-preview">
                <div class="apk-file-icon">📱</div>
                <div class="apk-file-details">
                    <div class="apk-file-name" id="apk-file-name">app-release.apk</div>
                    <div class="apk-file-size" id="apk-file-size">45.2 MB</div>
                    <div class="apk-upload-progress" id="apk-progress">
                        <div class="apk-upload-bar" id="apk-progress-bar"></div>
                    </div>
                </div>
                <button type="button" class="apk-file-remove" id="apk-remove-btn">Remove</button>
            </div>
        </div>
    `;

    // Insert dropzone before the original input
    fileContainer.insertAdjacentHTML('afterbegin', dropzoneHtml);

    // Elements
    const dropzone = document.getElementById('apk-dropzone');
    const preview = document.getElementById('apk-preview');
    const fileNameEl = document.getElementById('apk-file-name');
    const fileSizeEl = document.getElementById('apk-file-size');
    const removeBtn = document.getElementById('apk-remove-btn');
    const progressContainer = document.getElementById('apk-progress');
    const progressBar = document.getElementById('apk-progress-bar');
    const form = document.getElementById('appupdate_form'); // Django's default change form ID

    // Check if there's already a file (edit mode)
    const existingFileLink = fileContainer.querySelector('.file-upload a');
    if (existingFileLink) {
        const fullUrl = existingFileLink.href;
        const filename = fullUrl.substring(fullUrl.lastIndexOf('/') + 1);
        showFile(filename, "Previously uploaded file");
    }

    // ─── Event Listeners ───

    // Click to open file dialog
    dropzone.addEventListener('click', () => originalInput.click());

    // Drag events
    ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(eventName => {
        dropzone.addEventListener(eventName, preventDefaults, false);
    });

    function preventDefaults(e) {
        e.preventDefault();
        e.stopPropagation();
    }

    ['dragenter', 'dragover'].forEach(eventName => {
        dropzone.addEventListener(eventName, () => dropzone.classList.add('drag-over'), false);
    });

    ['dragleave', 'drop'].forEach(eventName => {
        dropzone.addEventListener(eventName, () => dropzone.classList.remove('drag-over'), false);
    });

    // Handle Drop
    dropzone.addEventListener('drop', (e) => {
        const dt = e.dataTransfer;
        const files = dt.files;
        
        if (files.length) {
            originalInput.files = files; // Assign to original input
            handleFiles(files[0]);
        }
    });

    // Handle Input Change (from Browse)
    originalInput.addEventListener('change', function() {
        if (this.files && this.files.length > 0) {
            handleFiles(this.files[0]);
        }
    });

    // Remove File
    removeBtn.addEventListener('click', () => {
        originalInput.value = ''; // Clear input
        
        // Hide preview, show dropzone
        preview.classList.remove('active');
        dropzone.style.display = 'block';
        
        // If there's a clear checkbox (django default), check it
        const clearCheckbox = fileContainer.querySelector('input[type="checkbox"][name$="-clear"]');
        if (clearCheckbox) clearCheckbox.checked = true;
    });

    // Simulated Progress on Submit
    if (form) {
        form.addEventListener('submit', function(e) {
            if (originalInput.files && originalInput.files.length > 0) {
                // Show progress bar
                progressContainer.classList.add('active');
                
                // Animate progress to 90% (real progress requires ajax, we just simulate)
                progressBar.style.width = '0%';
                setTimeout(() => progressBar.style.width = '30%', 100);
                setTimeout(() => progressBar.style.width = '60%', 500);
                setTimeout(() => progressBar.style.width = '90%', 1000);
                // The remaining 10% happens when page reloads
            }
        });
    }

    // ─── Helpers ───
    function handleFiles(file) {
        // Validation
        if (!file.name.toLowerCase().endsWith('.apk')) {
            alert('Only .apk files are allowed!');
            originalInput.value = '';
            return;
        }

        const sizeMB = file.size / (1024 * 1024);
        if (sizeMB > 200) {
            alert(`File is too large (${sizeMB.toFixed(1)} MB). Maximum size is 200 MB.`);
            originalInput.value = '';
            return;
        }

        showFile(file.name, formatBytes(file.size));
        
        // Uncheck clear checkbox if we selected a new file
        const clearCheckbox = fileContainer.querySelector('input[type="checkbox"][name$="-clear"]');
        if (clearCheckbox) clearCheckbox.checked = false;
        
        // If version is empty, try to guess from filename (e.g. app-release-1.2.3.apk -> 1.2.3)
        const versionInput = document.getElementById('id_version');
        if (versionInput && !versionInput.value) {
            const match = file.name.match(/(?:v|-|_)?(\d+\.\d+\.\d+)/i);
            if (match) versionInput.value = match[1];
        }
    }

    function showFile(name, sizeStr) {
        fileNameEl.textContent = name;
        fileSizeEl.textContent = sizeStr;
        
        // Show preview, hide dropzone
        dropzone.style.display = 'none';
        preview.classList.add('active');
        progressContainer.classList.remove('active');
        progressBar.style.width = '0%';
    }

    function formatBytes(bytes, decimals = 2) {
        if (bytes === 0) return '0 Bytes';
        const k = 1024;
        const dm = decimals < 0 ? 0 : decimals;
        const sizes = ['Bytes', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
    }
});
